            Tags = """["announcements","admin","reference"]""",
            ContentJson = """{"title":"Announcements Admin Field Reference","groups":[{"heading":"Panel Tabs","items":[{"label":"Announcements","value":"The default tab. Lists every sent announcement and holds the New Announcement button."},{"label":"Templates","value":"Reusable announcement presets. Holds the New Template button. Templates prefill the Send Announcement dialog."}]},{"heading":"Sent-Announcements List — Columns","items":[{"label":"Title","value":"Sortable. The announcement headline."},{"label":"Severity","value":"Sortable, filterable (enum). A colored chip: Critical (red), Warning (amber), Info (blue). Width: 100px."},{"label":"Scope","value":"Sortable. The audience: Company-Wide, Selected Teams, Individual Team, or Team Leads Only. Width: 140px."},{"label":"Sent By","value":"Sortable. Name of the admin or manager who created the announcement. Width: 140px."},{"label":"Sent","value":"Sortable, date type. When it was sent (MM/dd/yyyy hh:mm). Width: 140px."},{"label":"Acks","value":"Sortable, number type. Count of people who have acknowledged. Width: 80px."},{"label":"Actions (eye icon)","value":"Opens the Acknowledgments roster dialog. Clicking the row itself does the same. Width: 60px."}]},{"heading":"Send Announcement Dialog — Fields","items":[{"label":"Template","value":"Optional dropdown. Selecting a template prefills Content, Severity, Scope, and the acknowledgment toggle. You can still edit every field afterward. '-- None --' starts blank."},{"label":"Title (required)","value":"Text input, up to 200 characters. The headline recipients see."},{"label":"Content (required)","value":"Textarea, up to 5,000 characters. The body of the message."},{"label":"Severity (required)","value":"Dropdown: Info, Warning, Critical. Default Info. Colors the chip and signals urgency; does not change the audience."},{"label":"Scope (required)","value":"Dropdown: Company-Wide, Selected Teams, Individual Team, Team Leads Only. Default Company-Wide."},{"label":"Target Teams","value":"Multi-select. Appears only when Scope is Selected Teams or Individual Team. Pick the team(s) the announcement targets."},{"label":"Expires At","value":"Optional date picker. After this date the announcement stops surfacing; the record and its roster remain. Blank = no expiry."},{"label":"Require Acknowledgment","value":"Toggle. When on, recipients must acknowledge and you can track who did via the roster and the Acks count."},{"label":"Send button (campaign icon)","value":"Broadcasts the announcement immediately. Disabled until Title and Content are filled."}]},{"heading":"Scope Options","items":[{"label":"Company-Wide","value":"Everyone in the company. No team selection needed."},{"label":"Selected Teams","value":"Members of one or more teams chosen in Target Teams."},{"label":"Individual Team","value":"A single team chosen in Target Teams."},{"label":"Team Leads Only","value":"Only the leads of the target teams, not every member."}]},{"heading":"Severity Levels","items":[{"label":"Info","value":"Blue chip. Routine notices. Default severity."},{"label":"Warning","value":"Amber chip. Important but non-urgent."},{"label":"Critical","value":"Red chip. Urgent; usually paired with Require Acknowledgment."}]},{"heading":"Acknowledgments Roster Dialog","items":[{"label":"Header count","value":"'N acknowledged' — how many people have acknowledged the announcement."},{"label":"Acknowledgment required note","value":"Shown when the announcement required acknowledgment."},{"label":"Roster list","value":"Each person who acknowledged, with their name and the date/time they acknowledged (MM/dd/yyyy hh:mm)."},{"label":"Empty state","value":"'No acknowledgments yet' when no one has acknowledged."},{"label":"Close","value":"Dismisses the dialog."}]},{"heading":"Template Fields (New Template Dialog)","items":[{"label":"Name (required)","value":"Text input, up to 200 characters. How the template shows in the Templates list and the Template dropdown."},{"label":"Content (required)","value":"Textarea, up to 5,000 characters. The default body text the template provides."},{"label":"Default Severity (required)","value":"Dropdown: Info, Warning, Critical. The severity prefilled when the template is chosen."},{"label":"Default Scope (required)","value":"Dropdown: Company-Wide, Selected Teams, Individual Team, Team Leads Only. The scope prefilled when the template is chosen."},{"label":"Require Acknowledgment by Default","value":"Toggle. Whether the acknowledgment toggle starts on when this template is used."},{"label":"Create Template button","value":"Saves the template. Disabled until Name and Content are filled."}]},{"heading":"Templates List — Columns","items":[{"label":"Name","value":"Sortable. The template name."},{"label":"Severity","value":"Sortable. The template's default severity chip. Width: 100px."},{"label":"Scope","value":"Sortable. The template's default scope. Width: 140px."},{"label":"Ack Required","value":"'Yes' (warning chip) or 'No' — the template's default acknowledgment setting. Width: 110px."},{"label":"Actions (delete icon)","value":"Deletes the template after a confirm. Does not affect already-sent announcements. Width: 60px."}]},{"heading":"Roles & Permissions","items":[{"label":"Send an announcement","value":"Admin or Manager."},{"label":"View the sent list & acknowledgments","value":"Admin or Manager."},{"label":"Create or delete a template","value":"Admin only."},{"label":"Receive / acknowledge announcements","value":"Any user in the announcement's scope."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required. Max 200 characters."},{"label":"Content","value":"Required. Max 5,000 characters."},{"label":"Severity","value":"Required. One of Info, Warning, Critical."},{"label":"Scope","value":"Required. One of the four scope options."},{"label":"Target Teams","value":"Required when Scope is a team-based scope (so the announcement has a defined audience)."},{"label":"Template Name / Content","value":"Both required. Name and Content max 200 / 5,000 characters respectively."}]},{"heading":"Real-Time Behavior","items":[{"label":"Instant delivery","value":"A sent announcement is pushed to its audience immediately (real-time) and surfaces as an overlay banner."},{"label":"Live list updates","value":"New announcements appear at the top of the sent list in real time, including ones sent by a colleague while you are viewing the list."}]}]}"""
