            AppRoutes = """["/admin/announcements"]""",
            Tags = """["announcements","admin","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":7,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ann1","text":"Where do you compose and manage company announcements?","options":[{"id":"a","text":"In the Chat panel — type the message in any channel and mark it as an announcement"},{"id":"b","text":"In Admin → Announcements, which has an Announcements tab and a Templates tab","isCorrect":true},{"id":"c","text":"In Notifications → Preferences"},{"id":"d","text":"On the Dashboard, via the Announcements widget"}],"explanation":"Announcements are composed and managed in the Admin > Announcements panel (route /admin/announcements). It has two tabs — Announcements (the sent list + New Announcement) and Templates. The Chat broadcast channel surfaces announcements, but you author and manage them here, not in Chat."},{"id":"ann2","text":"You want a Critical safety notice to go only to the leads of two specific teams. What Scope do you choose?","options":[{"id":"a","text":"Company-Wide"},{"id":"b","text":"Selected Teams"},{"id":"c","text":"Team Leads Only, then pick the two teams in Target Teams","isCorrect":true},{"id":"d","text":"Individual Team"}],"explanation":"Team Leads Only targets just the leads of the target teams rather than every member. The Target Teams multi-select appears so you can pick which teams' leads receive it. (Selected Teams would reach every member of those teams, not only the leads.)"},{"id":"ann3","text":"When does the Target Teams multi-select appear in the Send Announcement dialog?","options":[{"id":"a","text":"Always — every announcement must target at least one team"},{"id":"b","text":"Only when Scope is Selected Teams or Individual Team (the team-based scopes)","isCorrect":true},{"id":"c","text":"Only when Severity is set to Critical"},{"id":"d","text":"Only after you pick a template"}],"explanation":"Target Teams appears only for the team-based scopes — Selected Teams and Individual Team — so you can define which teams receive the announcement. For Company-Wide there is no team selection, and Team Leads Only also surfaces the team picker to choose whose leads are targeted."},{"id":"ann4","text":"How do you see exactly who has acknowledged an announcement you sent?","options":[{"id":"a","text":"Click the announcement's row (or its eye icon) to open the Acknowledgments roster dialog","isCorrect":true},{"id":"b","text":"Hover over the Acks number to see a tooltip list"},{"id":"c","text":"Export the announcement to CSV"},{"id":"d","text":"Check the Notifications panel for read receipts"}],"explanation":"Clicking a row (or the visibility/eye icon on it) opens the Acknowledgments dialog. It shows a count of how many acknowledged, whether acknowledgment was required, and each person's name with the date/time they acknowledged."},{"id":"ann5","text":"What does turning on 'Require Acknowledgment' actually do?","options":[{"id":"a","text":"It changes the announcement's audience to managers only"},{"id":"b","text":"It makes recipients click to acknowledge, so the Acks count and roster become meaningful tracking","isCorrect":true},{"id":"c","text":"It automatically deletes the announcement once everyone reads it"},{"id":"d","text":"It changes the severity chip to red"}],"explanation":"Require Acknowledgment makes recipients explicitly acknowledge the announcement. That is what populates the Acks count and the acknowledgment roster, letting you confirm a notice reached the people who needed to see it. Without it, people simply read the banner."},{"id":"ann6","text":"You send the same maintenance-window notice every month. What is the best way to speed that up?","options":[{"id":"a","text":"Copy and paste the text from an old chat message each time"},{"id":"b","text":"Create a Template on the Templates tab, then pick it in the Template dropdown when sending to prefill the fields","isCorrect":true},{"id":"c","text":"Edit a previously sent announcement and resend it"},{"id":"d","text":"There is no reuse — you must retype it every time"}],"explanation":"Save a reusable Template (name, default content, default severity, default scope, default acknowledgment setting) on the Templates tab. When sending, choosing that template in the Template dropdown prefills Content, Severity, Scope, and the acknowledgment toggle — you can edit any field before sending."},{"id":"ann7","text":"What does the Severity setting (Info / Warning / Critical) control?","options":[{"id":"a","text":"Who receives the announcement"},{"id":"b","text":"The urgency signal and the color of the chip — it does not change the audience","isCorrect":true},{"id":"c","text":"Whether the announcement expires"},{"id":"d","text":"Whether acknowledgment is required"}],"explanation":"Severity is a signal of urgency and what color the chip is (Info blue, Warning amber, Critical red). It is independent of audience (that's Scope), expiry (Expires At), and acknowledgment (Require Acknowledgment)."},{"id":"ann8","text":"A teammate sends an announcement while you are looking at the sent-announcements list. What happens?","options":[{"id":"a","text":"Nothing until you manually refresh the page"},{"id":"b","text":"It appears at the top of the list in real time","isCorrect":true},{"id":"c","text":"You are logged out and must sign back in to see it"},{"id":"d","text":"It only shows up after the announcement expires"}],"explanation":"The sent-announcements list updates in real time. A new announcement — including one sent by a colleague while you are viewing the list — is pushed to the top without a manual refresh."},{"id":"ann9","text":"You delete a template from the Templates tab. What happens to announcements already sent from it?","options":[{"id":"a","text":"They are retracted from everyone who received them"},{"id":"b","text":"They are unaffected — deleting a template does not touch announcements already sent","isCorrect":true},{"id":"c","text":"Their acknowledgment rosters are cleared"},{"id":"d","text":"They lose their severity and become Info"}],"explanation":"Deleting a template only removes the reusable preset. Announcements already sent from it remain in the sent list with their rosters and severity intact — the template is just a starting point for composing, not a live link to past sends."},{"id":"ann10","text":"Which roles can create and delete announcement templates?","options":[{"id":"a","text":"Any user"},{"id":"b","text":"Admin only","isCorrect":true},{"id":"c","text":"Admin or Manager"},{"id":"d","text":"Team leads"}],"explanation":"Sending announcements and viewing the sent list / acknowledgments is open to Admin or Manager, but creating and deleting templates is Admin-only."}]}"""
